# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

import android.content.Intent
import android.os.Bundle
import android.net.Uri
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareReceiverActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleIncomingShareIntent(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        if (intent != null) {
            handleIncomingShareIntent(intent)
        }
    }

    private fun handleIncomingShareIntent(intent: Intent) {
        if (Intent.ACTION_SEND == intent.action && intent.type != null) {
            when {
                intent.type.startsWith("text/") -> handleTextShare(intent)
                intent.type.startsWith("image/") -> handleImageShare(intent)
            }
        }
    }

    private fun handleTextShare(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        sharedText?.let {
            Toast.makeText(this, "Shared Text: $it", Toast.LENGTH_LONG).show()
        }
    }

    private fun handleImageShare(intent: Intent) {
        val imageUri: Uri? = intent.getParcelableExtra(Intent.EXTRA_STREAM)
        imageUri?.let {
            Toast.makeText(this, "Shared Image URI: $it", Toast.LENGTH_LONG).show()
        }
    }
}

<!-- In AndroidManifest.xml -->
<activity android:name=".ShareReceiverActivity">
    <intent-filter>
        <action android:name="android.intent.action.SEND" />
        <category android:name="android.intent.category.DEFAULT" />
        <data android:mimeType="text/plain" />
        <data android:mimeType="image/*" />
    </intent-filter>
</activity>